const item = $input.first().json;
const body = item.text || item.textPlain || item.snippet || item.body || '';
const sender = item.from || item.From || item.sender || '';
return [{ json: { original_inquiry: body, sender_email: sender, subject: item.subject || item.Subject || 'Customer inquiry', message_id: item.id || item.messageId || item.message_id || '', source_channel: 'gmail', execution_meta: { started_at: new Date().toISOString(), agent_durations: {} } } }];

const response = $input.first().json;
const message = response.choices?.[0]?.message || {};
const raw = message.content || response.output || response.message?.content || message.reasoning_content || '';
function extractJSON(text) {
  const value = String(text || '').trim();
  try { return JSON.parse(value); } catch {}
  const stripped = value.replace(/```(?:json)?\s*|\s*```/g, '').trim();
  try { return JSON.parse(stripped); } catch {}
  const fenced = value.match(/\{[\s\S]*\}/);
  if (fenced) { try { return JSON.parse(fenced[0]); } catch {} }
  return null;
}
const parsed = extractJSON(raw);
const required = ["type","priority","confidence"];
const missing = required.filter((key) => parsed?.[key] === undefined || parsed?.[key] === null || parsed?.[key] === '');
const ok = !!parsed && missing.length === 0;
const base = $('Normalize_Input').first().json;
return [{ json: { ...base, classification: parsed || {}, _ok: ok, _agent: 'classifier', _required: required, _missing: missing, _raw: ok ? undefined : String(raw || JSON.stringify(response)).substring(0, 1000) } }];

