const failed = $input.first().json;
const missing = Array.isArray(failed._missing) && failed._missing.length ? ` missing keys: ${failed._missing.join(', ')}` : '';
const required = Array.isArray(failed._required) ? ` required keys: ${failed._required.join(', ')}` : '';
const raw = failed._raw ? ` raw: ${failed._raw}` : '';
throw new Error(`Agent validation failed at ${failed._agent || 'unknown'}:${missing}.${required}.${raw}`);
